Gallery.Stylesheet:
.speSessionRow {
  display: flex;
  align-items: flex-start;
  gap: 8px;
}
.speSessionRow:hover {
  background-color: #eef5ff;
}
.speSessionRowSelected {
  border-left: 2px solid #BCE3EE;
  background: #f7fcfe;
}
.speSessionRowSelected:hover {
  background: #eaf6fb;
}
.speSessionIcon {
  flex: 0 0 auto;
  width: 24px;
  padding-top: 2px;
}
.speSessionBody {
  flex: 1 1 auto;
  min-width: 0;
}
.speSessionHeader {
  display: flex;
  align-items: center;
  gap: 6px;
}
.speSessionUser {
  flex: 1 1 auto;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.speSessionIdPill {
  border: 1px solid #BCE3EE;
  background: #DCF1F6;
  color: #267F98;
  padding: 1px 6px;
  border-radius: 3px;
  font-size: 10px;
  white-space: nowrap;
}
.speSessionLocation {
  color: #666;
  font-size: 11px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.speSessionKill,
.speSessionKillSlot {
  flex: 0 0 auto;
  width: 18px;
  height: 18px;
  padding: 0;
}
.speSessionKill {
  border: 0;
  background: transparent;
  color: #999;
  font-size: 14px;
  line-height: 18px;
  text-align: center;
  cursor: pointer;
  visibility: hidden;
  user-select: none;
}
.speSessionRow:hover .speSessionKill { visibility: visible; }
.speSessionKill:hover { color: #c00; }
